import React, { useEffect, useMemo, useState } from 'react';
import { api } from '@/lib/api';
import { ensureSession } from '@/lib/auth';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { QRCodeSVG } from 'qrcode.react';
import {
  AlertCircle, BarChart3, Building2, Calendar, CheckCircle2, ChevronLeft,
  ChevronRight, CreditCard, DoorOpen, Download, Edit3, FileText, Mail, MapPin,
  Phone, Plus, Printer, QrCode, Receipt, RefreshCw, Search, Settings, Trash2,
  UserCheck, Users, Wrench, X,
} from 'lucide-react';

type Tab = 'dashboard' | 'properties' | 'units' | 'tenants' | 'leases' | 'rent' | 'maintenance' | 'vendors' | 'applications' | 'settings';
type EntityKind = 'property' | 'unit' | 'tenant' | 'lease' | 'workOrder' | 'vendor' | 'application';
type DetailKind = 'property' | 'tenant' | 'workOrder' | 'vendor' | 'application';

type Property = { id: string; name: string; type: string; address: string; city: string; units: number; occupied: number; monthlyIncome: number; notes: string; color: string };
type Unit = { id: string; propertyId: string; number: string; type: string; beds: number; baths: number; sqft: number; rent: number; status: string; tenantId?: string; tenantName?: string; notes?: string };
type Tenant = { id: string; name: string; phone: string; email: string; propertyId: string; unitId: string; unit: string; leaseStart: string; leaseEnd: string; monthlyRent: number; status: string; shortCode: string; paid: number; balance: number; employer: string; income: number; emergency: string; notes: string };
type Lease = { id: string; tenantId: string; unitId: string; start: string; end: string; rent: number; deposit: number; dueDay: number; lateFee: number; status: string; notes: string };
type Charge = { id: string; leaseId: string; tenantId: string; unitId: string; period: string; dueDate: string; amount: number; paid: number; status: string; waived?: boolean };
type Payment = { id: string; chargeId?: string; tenantId: string; unitId: string; amount: number; method: string; paidAt: string; reference: string; notes: string };
type Vendor = { id: string; name: string; category: string; phone: string; email: string; notes: string; color: string };
type WorkOrder = { id: string; propertyId: string; unitId: string; tenantId: string; vendorId: string; title: string; description: string; priority: string; status: string; scheduledAt: string; completedAt: string; cost: number; notes: string };
type Application = { id: string; unitId: string; firstName: string; lastName: string; phone: string; email: string; employer: string; income: number; desiredMoveIn: string; status: string; notes: string };
type Policy = { dueDay: number; lateFee: number; graceDays: number; currency: string; reminders: string; invoicePrefix: string };
type Data = { properties: Property[]; units: Unit[]; tenants: Tenant[]; leases: Lease[]; charges: Charge[]; payments: Payment[]; vendors: Vendor[]; workOrders: WorkOrder[]; applications: Application[]; policy: Policy };

type ApiProperty = { id: string; name: string; address: string; type: 'residential' | 'commercial' | 'mixed'; totalUnits: number };
type ApiUnit = { id: string; propertyId: string; unitNumber: string; rentAmount: number; status: 'vacant' | 'occupied' | 'maintenance' };
type ApiTenant = { id: string; unitId?: string | null; name: string; phone: string; email?: string | null; leaseStart?: string | null; leaseEnd?: string | null; status: 'active' | 'past' | 'pending' };
type ApiPayment = { id: string; tenantId: string; unitId: string; amount: number; forMonth: string; paidAt: string; method: string; reference?: string | null };

const now = new Date();
const year = now.getFullYear();
const currentPeriod = `${year}-${String(now.getMonth() + 1).padStart(2, '0')}`;
const currency = (n: number, cur = 'TZS') => `${cur} ${Math.round(n || 0).toLocaleString()}`;
const uid = (p: string) => `${p}-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 6)}`;
const initials = (name: string) => name.split(' ').map((x) => x[0]).join('').slice(0, 2).toUpperCase();
const periodLabel = (p: string) => new Date(`${p}-01`).toLocaleDateString('en-GB', { month: 'short', year: 'numeric' });
const nextPeriod = (p: string, add: number) => { const [y, m] = p.split('-').map(Number); const d = new Date(y, m - 1 + add, 1); return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`; };
const toCsv = (rows: Record<string, unknown>[]) => rows.map((r) => Object.values(r).map((v) => `"${String(v ?? '').replace(/"/g, '""')}"`).join(',')).join('\n');

