export default function OpenPropertyComplete() {
  const [data, setData] = useState<Data>(seedData);
  const [tab, setTab] = useState<Tab>('dashboard');
  const [query, setQuery] = useState('');
  const [period, setPeriod] = useState(currentPeriod);
  const [toast, setToast] = useState('Open Property frontend completed for KobeOS.');
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState<{ kind: EntityKind; id?: string } | null>(null);
  const [detail, setDetail] = useState<{ kind: DetailKind; id: string } | null>(null);
  const [paymentTarget, setPaymentTarget] = useState<{ tenantId: string; chargeId?: string; amount: number } | null>(null);

  useEffect(() => { void syncExistingApi(); }, []);

  async function syncExistingApi() {
    setLoading(true);
    try {
      await ensureSession();
      const [props, unitsRaw, tenantsRaw, paymentsRaw] = await Promise.all([
        api<ApiProperty[]>('/property/properties'),
        api<ApiUnit[]>('/property/units'),
        api<ApiTenant[]>('/property/tenants'),
        api<ApiPayment[]>('/property/payments'),
      ]);
      if (!props.length && !unitsRaw.length && !tenantsRaw.length) {
        setToast('Backend reachable but property tables are empty. Using full frontend demo data.');
        return;
      }
      setData((old) => {
        const units = unitsRaw.map<Unit>((u) => ({ id: u.id, propertyId: u.propertyId, number: u.unitNumber, type: 'Unit', beds: 0, baths: 1, sqft: 0, rent: Number(u.rentAmount || 0), status: u.status === 'occupied' ? 'Occupied' : u.status === 'maintenance' ? 'Maintenance' : 'Vacant', notes: '' }));
        const tenants = tenantsRaw.map<Tenant>((t) => {
          const unit = units.find((u) => u.id === t.unitId);
          const paid = paymentsRaw.filter((p) => p.tenantId === t.id).reduce((s, p) => s + Number(p.amount || 0), 0);
          const annual = (unit?.rent || 0) * 12;
          return { id: t.id, name: t.name, phone: t.phone, email: t.email || '', propertyId: unit?.propertyId || '', unitId: unit?.id || '', unit: unit?.number || '', leaseStart: t.leaseStart || '', leaseEnd: t.leaseEnd || '', monthlyRent: unit?.rent || 0, status: t.status === 'pending' ? 'Pending' : t.status === 'past' ? 'Past' : 'Active', shortCode: `KBE${t.id.replace(/-/g, '').slice(0, 6).toUpperCase()}`, paid, balance: Math.max(annual - paid, 0), employer: '', income: 0, emergency: '', notes: '' };
        });
        const properties = props.map<Property>((p, i) => { const propUnits = units.filter((u) => u.propertyId === p.id); return { id: p.id, name: p.name, type: p.type, address: p.address, city: '', units: p.totalUnits || propUnits.length, occupied: propUnits.filter((u) => u.status === 'Occupied').length, monthlyIncome: propUnits.reduce((s, u) => s + u.rent, 0), color: ['blue', 'emerald', 'amber', 'violet'][i % 4], notes: '' }; });
        const leases = tenants.map<Lease>((t) => ({ id: `l-${t.id}`, tenantId: t.id, unitId: t.unitId, start: t.leaseStart, end: t.leaseEnd, rent: t.monthlyRent, deposit: t.monthlyRent, dueDay: old.policy.dueDay, lateFee: old.policy.lateFee, status: 'Active', notes: '' }));
        const charges = generateChargesFor(leases, period);
        const payments = paymentsRaw.map<Payment>((p) => ({ id: p.id, tenantId: p.tenantId, unitId: p.unitId, amount: Number(p.amount || 0), method: p.method || 'Cash', paidAt: p.paidAt, reference: p.reference || '', notes: '' }));
        return { ...old, properties, units, tenants, leases, charges, payments };
      });
      setToast('Synced existing KobeOS property API data. Frontend-only modules remain local until backend routes are added.');
    } catch (err) {
      setToast(`Offline/demo mode: ${(err as Error).message}`);
    } finally {
      setLoading(false);
    }
  }

  function generateChargesFor(leases: Lease[], p: string): Charge[] {
    return leases.map((l) => ({ id: `charge-${p}-${l.id}`, leaseId: l.id, tenantId: l.tenantId, unitId: l.unitId, period: p, dueDate: `${p}-${String(l.dueDay || data.policy.dueDay).padStart(2, '0')}`, amount: l.rent, paid: 0, status: 'Open' }));
  }

  function upsert(kind: EntityKind, id: string | undefined, values: Record<string, string>) {
    setData((old) => {
      const updateById = <T extends { id: string }>(rows: T[], row: T) => id ? rows.map((r) => r.id === id ? row : r) : [row, ...rows];
      if (kind === 'property') {
        const row: Property = { id: id || uid('p'), name: values.name || 'New Property', type: values.type || 'Residential', address: values.address || '', city: values.city || '', units: Number(values.units || 0), occupied: Number(values.occupied || 0), monthlyIncome: Number(values.monthlyIncome || 0), notes: values.notes || '', color: values.color || 'blue' };
        return { ...old, properties: updateById(old.properties, row) };
      }
      if (kind === 'unit') {
        const propertyId = values.propertyId || old.properties[0]?.id || '';
        const row: Unit = { id: id || uid('u'), propertyId, number: values.number || 'Unit', type: values.type || 'Unit', beds: Number(values.beds || 0), baths: Number(values.baths || 1), sqft: Number(values.sqft || 0), rent: Number(values.rent || 0), status: values.status || 'Vacant', tenantId: values.tenantId || '', tenantName: old.tenants.find((t) => t.id === values.tenantId)?.name || '', notes: values.notes || '' };
        return { ...old, units: updateById(old.units, row) };
      }
      if (kind === 'tenant') {
        const unit = old.units.find((u) => u.id === values.unitId);
        const name = values.name || 'New Tenant';
        const row: Tenant = { id: id || uid('t'), name, phone: values.phone || '', email: values.email || '', propertyId: unit?.propertyId || values.propertyId || '', unitId: values.unitId || '', unit: unit?.number || values.unit || '', leaseStart: values.leaseStart || '', leaseEnd: values.leaseEnd || '', monthlyRent: Number(values.monthlyRent || unit?.rent || 0), status: values.status || 'Active', shortCode: values.shortCode || `KBE${Date.now().toString().slice(-6)}`, paid: Number(values.paid || 0), balance: Number(values.balance || 0), employer: values.employer || '', income: Number(values.income || 0), emergency: values.emergency || '', notes: values.notes || '' };
        return { ...old, tenants: updateById(old.tenants, row), units: old.units.map((u) => u.id === row.unitId ? { ...u, status: 'Occupied', tenantId: row.id, tenantName: row.name } : u) };
      }
      if (kind === 'lease') {
        const row: Lease = { id: id || uid('l'), tenantId: values.tenantId || '', unitId: values.unitId || '', start: values.start || '', end: values.end || '', rent: Number(values.rent || 0), deposit: Number(values.deposit || 0), dueDay: Number(values.dueDay || old.policy.dueDay), lateFee: Number(values.lateFee || old.policy.lateFee), status: values.status || 'Active', notes: values.notes || '' };
        return { ...old, leases: updateById(old.leases, row) };
      }
      if (kind === 'workOrder') {
        const row: WorkOrder = { id: id || uid('wo'), propertyId: values.propertyId || '', unitId: values.unitId || '', tenantId: values.tenantId || '', vendorId: values.vendorId || '', title: values.title || 'Work order', description: values.description || '', priority: values.priority || 'Normal', status: values.status || 'Open', scheduledAt: values.scheduledAt || '', completedAt: values.completedAt || '', cost: Number(values.cost || 0), notes: values.notes || '' };
        return { ...old, workOrders: updateById(old.workOrders, row) };
      }
      if (kind === 'vendor') {
        const row: Vendor = { id: id || uid('v'), name: values.name || 'Vendor', category: values.category || 'General', phone: values.phone || '', email: values.email || '', notes: values.notes || '', color: values.color || 'blue' };
        return { ...old, vendors: updateById(old.vendors, row) };
      }
      const row: Application = { id: id || uid('a'), unitId: values.unitId || '', firstName: values.firstName || '', lastName: values.lastName || '', phone: values.phone || '', email: values.email || '', employer: values.employer || '', income: Number(values.income || 0), desiredMoveIn: values.desiredMoveIn || '', status: values.status || 'New', notes: values.notes || '' };
      return { ...old, applications: updateById(old.applications, row) };
    });
    setToast(`${kind} saved.`);
    setForm(null);
  }

  function remove(kind: EntityKind, id: string) {
    if (!window.confirm('Delete this record?')) return;
    setData((old) => ({
      ...old,
      properties: kind === 'property' ? old.properties.filter((x) => x.id !== id) : old.properties,
      units: kind === 'unit' ? old.units.filter((x) => x.id !== id) : old.units,
      tenants: kind === 'tenant' ? old.tenants.filter((x) => x.id !== id) : old.tenants,
      leases: kind === 'lease' ? old.leases.filter((x) => x.id !== id) : old.leases,
      workOrders: kind === 'workOrder' ? old.workOrders.filter((x) => x.id !== id) : old.workOrders,
      vendors: kind === 'vendor' ? old.vendors.filter((x) => x.id !== id) : old.vendors,
      applications: kind === 'application' ? old.applications.filter((x) => x.id !== id) : old.applications,
    }));
    setToast(`${kind} deleted.`);
  }

  async function savePayment(values: { amount: number; method: string; reference: string; notes: string }) {
    const tenant = data.tenants.find((t) => t.id === paymentTarget?.tenantId);
    if (!tenant || !values.amount) return;
    const payment: Payment = { id: uid('pay'), chargeId: paymentTarget?.chargeId, tenantId: tenant.id, unitId: tenant.unitId, amount: values.amount, method: values.method, paidAt: new Date().toISOString(), reference: values.reference, notes: values.notes };
    try {
      await api('/property/payments', { method: 'POST', body: JSON.stringify({ tenantId: tenant.id, unitId: tenant.unitId, amount: values.amount, currency: data.policy.currency, forMonth: `${period}-01`, paidAt: payment.paidAt, method: values.method, reference: values.reference }) });
      setToast('Payment saved to KobeOS backend.');
    } catch (err) {
      setToast(`Payment saved locally/offline: ${(err as Error).message}`);
    }
    setData((old) => ({ ...old, payments: [payment, ...old.payments], tenants: old.tenants.map((t) => t.id === tenant.id ? { ...t, paid: t.paid + values.amount, balance: Math.max(t.balance - values.amount, 0), status: Math.max(t.balance - values.amount, 0) ? t.status : 'Active' } : t), charges: old.charges.map((c) => c.id === payment.chargeId ? normalizeCharge({ ...c, paid: c.paid + values.amount }) : c) }));
    setPaymentTarget(null);
  }

  function removePayment(id: string) {
    const pay = data.payments.find((p) => p.id === id);
    if (!pay) return;
    setData((old) => ({ ...old, payments: old.payments.filter((p) => p.id !== id), charges: old.charges.map((c) => c.id === pay.chargeId ? normalizeCharge({ ...c, paid: Math.max(0, c.paid - pay.amount) }) : c), tenants: old.tenants.map((t) => t.id === pay.tenantId ? { ...t, paid: Math.max(0, t.paid - pay.amount), balance: t.balance + pay.amount } : t) }));
    setToast('Payment removed from frontend ledger.');
  }

  function generateCharges() {
    const existing = new Set(data.charges.filter((c) => c.period === period).map((c) => c.leaseId));
    const rows = generateChargesFor(data.leases.filter((l) => !existing.has(l.id)), period);
    setData((old) => ({ ...old, charges: [...rows, ...old.charges] }));
    setToast(rows.length ? `${rows.length} rent charges generated.` : 'Charges already exist for this period.');
  }

  function waiveCharge(id: string) {
    setData((old) => ({ ...old, charges: old.charges.map((c) => c.id === id ? { ...c, status: 'Waived', waived: true } : c) }));
    setToast('Charge waived.');
  }

  function approveApplication(id: string) {
    const app = data.applications.find((a) => a.id === id);
    const unit = data.units.find((u) => u.id === app?.unitId);
    if (!app || !unit) return;
    const tenantId = uid('t');
    const tenant: Tenant = { id: tenantId, name: `${app.firstName} ${app.lastName}`, phone: app.phone, email: app.email, propertyId: unit.propertyId, unitId: unit.id, unit: unit.number, leaseStart: app.desiredMoveIn, leaseEnd: `${year + 1}-${String(now.getMonth() + 1).padStart(2, '0')}-01`, monthlyRent: unit.rent, status: 'Active', shortCode: `KBE${Date.now().toString().slice(-6)}`, paid: 0, balance: unit.rent * 12, employer: app.employer, income: app.income, emergency: '', notes: app.notes };
    const lease: Lease = { id: uid('l'), tenantId, unitId: unit.id, start: tenant.leaseStart, end: tenant.leaseEnd, rent: unit.rent, deposit: unit.rent, dueDay: data.policy.dueDay, lateFee: data.policy.lateFee, status: 'Active', notes: '' };
    setData((old) => ({ ...old, tenants: [tenant, ...old.tenants], leases: [lease, ...old.leases], applications: old.applications.map((a) => a.id === id ? { ...a, status: 'Approved' } : a), units: old.units.map((u) => u.id === unit.id ? { ...u, status: 'Occupied', tenantId, tenantName: tenant.name } : u) }));
    setToast('Application approved and converted into tenant + lease.');
  }

  function exportCsv(name: string, rows: Record<string, unknown>[]) {
    const blob = new Blob([toCsv(rows)], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = `${name}.csv`; a.click(); URL.revokeObjectURL(url);
  }

  const stats = useMemo(() => ({ units: data.units.length, occupied: data.units.filter((u) => u.status === 'Occupied').length, rent: data.charges.filter((c) => c.period === period).reduce((s, c) => s + c.amount, 0), collected: data.charges.filter((c) => c.period === period).reduce((s, c) => s + c.paid, 0), overdue: data.charges.filter((c) => c.status === 'Overdue').length, orders: data.workOrders.filter((w) => !['Completed', 'Cancelled'].includes(w.status)).length }), [data, period]);
  const searchResults = useMemo(() => globalResults(data, query), [data, query]);

  const nav: Array<[Tab, string, React.ComponentType<{ className?: string }>]> = [['dashboard', 'Dashboard', BarChart3], ['properties', 'Properties', Building2], ['units', 'Units', DoorOpen], ['tenants', 'Tenants', Users], ['leases', 'Leases', FileText], ['rent', 'Rent Ledger', Receipt], ['maintenance', 'Maintenance', Wrench], ['vendors', 'Vendors', UserCheck], ['applications', 'Applications', UserCheck], ['settings', 'Policy', Settings]];

  return <div className="flex h-full min-h-0 bg-[#080b12] text-white">
    <aside className="hidden w-64 shrink-0 border-r border-white/10 bg-[#0d111b] p-3 md:flex md:flex-col">
      <div className="mb-4 rounded-2xl border border-white/10 bg-white/[0.03] p-3"><div className="font-semibold">Open Property</div><div className="text-[11px] text-white/40">Complete KobeOS frontend</div></div>
      <div className="space-y-1">{nav.map(([key, label, Icon]) => <button key={key} onClick={() => setTab(key)} className={`flex w-full items-center gap-2 rounded-xl px-3 py-2 text-left text-xs ${tab === key ? 'bg-blue-500/15 text-blue-300' : 'text-white/55 hover:bg-white/[0.04]'}`}><Icon className="h-4 w-4" />{label}</button>)}</div>
      <div className="mt-auto rounded-2xl border border-white/10 bg-white/[0.03] p-3 text-[11px] text-white/45">{toast}</div>
    </aside>
    <main className="flex min-w-0 flex-1 flex-col">
      <header className="border-b border-white/10 bg-[#0b0f18] p-4">
        <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
          <div><div className="font-semibold">Property Management</div><div className="text-[11px] text-white/40">Forms, details, applications, rent ledger, maintenance and settings are now available.</div></div>
          <div className="relative flex gap-2"><Search className="absolute left-3 top-2.5 h-4 w-4 text-white/30" /><Input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Search everything..." className="h-9 w-72 rounded-xl border-white/10 bg-white/[0.04] pl-9 text-xs text-white" />{query && <SearchBox results={searchResults} open={(r) => { setTab(r.tab); if (r.detail) setDetail(r.detail); setQuery(''); }} />}<Button onClick={syncExistingApi} disabled={loading} className="h-9 rounded-xl bg-blue-500 text-xs">{loading ? <RefreshCw className="h-4 w-4 animate-spin" /> : <RefreshCw className="h-4 w-4" />}</Button></div>
        </div>
        <div className="mt-3 flex gap-1 overflow-x-auto md:hidden">{nav.map(([key, label, Icon]) => <button key={key} onClick={() => setTab(key)} className={`shrink-0 rounded-lg border px-2 py-1 text-[10px] ${tab === key ? 'border-blue-500/25 bg-blue-500/15 text-blue-300' : 'border-white/10 text-white/50'}`}><Icon className="mr-1 inline h-3 w-3" />{label}</button>)}</div>
      </header>
      <ScrollArea className="min-h-0 flex-1"><div className="p-4">
        {tab === 'dashboard' && <Dashboard stats={stats} data={data} period={period} setTab={setTab} openPayment={(tenantId, amount) => setPaymentTarget({ tenantId, amount })} />}
        {tab === 'properties' && <PropertiesPage data={data} setForm={setForm} setDetail={setDetail} remove={remove} query={query} />}
        {tab === 'units' && <UnitsPage data={data} setForm={setForm} remove={remove} query={query} />}
        {tab === 'tenants' && <TenantsPage data={data} setForm={setForm} setDetail={setDetail} remove={remove} openPayment={(tenantId, amount) => setPaymentTarget({ tenantId, amount })} query={query} />}
        {tab === 'leases' && <LeasesPage data={data} setForm={setForm} remove={remove} />}
        {tab === 'rent' && <RentPage data={data} period={period} setPeriod={setPeriod} generate={generateCharges} openPayment={(tenantId, chargeId, amount) => setPaymentTarget({ tenantId, chargeId, amount })} removePayment={removePayment} waive={waiveCharge} exportCsv={exportCsv} />}
        {tab === 'maintenance' && <MaintenancePage data={data} setForm={setForm} setDetail={setDetail} remove={remove} />}
        {tab === 'vendors' && <VendorsPage data={data} setForm={setForm} setDetail={setDetail} remove={remove} />}
        {tab === 'applications' && <ApplicationsPage data={data} setForm={setForm} setDetail={setDetail} remove={remove} approve={approveApplication} />}
        {tab === 'settings' && <SettingsPage data={data} setData={setData} exportCsv={exportCsv} />}
      </div></ScrollArea>
    </main>
    {form && <EntityForm data={data} target={form} close={() => setForm(null)} save={upsert} />}
    {detail && <DetailModal data={data} target={detail} close={() => setDetail(null)} setForm={setForm} openPayment={(tenantId, amount) => setPaymentTarget({ tenantId, amount })} />}
    {paymentTarget && <PaymentModal data={data} target={paymentTarget} close={() => setPaymentTarget(null)} save={savePayment} />}
  </div>;
}

function normalizeCharge(c: Charge): Charge { if (c.waived) return { ...c, status: 'Waived' }; if (c.paid >= c.amount) return { ...c, status: 'Paid' }; if (c.paid > 0) return { ...c, status: 'Partial' }; return { ...c, status: new Date(c.dueDate).getTime() < Date.now() ? 'Overdue' : 'Open' }; }
function propertyName(data: Data, id?: string) { return data.properties.find((p) => p.id === id)?.name || 'No property'; }
function unitName(data: Data, id?: string) { return data.units.find((u) => u.id === id)?.number || 'No unit'; }
function tenantName(data: Data, id?: string) { return data.tenants.find((t) => t.id === id)?.name || 'No tenant'; }
function vendorName(data: Data, id?: string) { return data.vendors.find((v) => v.id === id)?.name || 'No vendor'; }
function badgeTone(s: string) { if (['Late', 'Overdue', 'High', 'Urgent', 'Missing', 'Declined'].includes(s)) return 'bg-red-500/10 text-red-300 border-red-500/20'; if (['Active', 'Paid', 'Completed', 'Approved', 'Occupied'].includes(s)) return 'bg-emerald-500/10 text-emerald-300 border-emerald-500/20'; if (['Partial', 'Pending', 'Screening', 'Assigned'].includes(s)) return 'bg-amber-500/10 text-amber-300 border-amber-500/20'; return 'bg-blue-500/10 text-blue-300 border-blue-500/20'; }
function Badge({ s }: { s: string }) { return <span className={`inline-flex rounded-full border px-2 py-0.5 text-[10px] font-semibold ${badgeTone(s)}`}>{s}</span>; }
function Title({ title, sub, action, onAction }: { title: string; sub: string; action?: string; onAction?: () => void }) { return <div className="mb-3 flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between"><div><h2 className="text-lg font-semibold">{title}</h2><p className="text-xs text-white/40">{sub}</p></div>{action && <Button onClick={onAction} className="w-fit rounded-xl bg-blue-500"><Plus className="mr-1 h-3.5 w-3.5" />{action}</Button>}</div>; }
function Panel({ title, children, action }: { title: string; children: React.ReactNode; action?: React.ReactNode }) { return <Card className="border-white/10 bg-white/[0.03]"><CardHeader className="flex flex-row items-center justify-between px-4 py-3"><CardTitle className="text-sm">{title}</CardTitle>{action}</CardHeader><CardContent className="px-4 pb-4">{children}</CardContent></Card>; }
function Metric({ label, value, sub }: { label: string; value: React.ReactNode; sub: string }) { return <Card className="border-white/10 bg-white/[0.03]"><CardContent className="p-4"><div className="text-[10px] uppercase tracking-wider text-white/35">{label}</div><div className="mt-1 text-xl font-bold">{value}</div><div className="text-xs text-white/40">{sub}</div></CardContent></Card>; }
function RowActions({ edit, del, view }: { edit?: () => void; del?: () => void; view?: () => void }) { return <div className="flex justify-end gap-1">{view && <IconBtn onClick={view} label="View" icon={<FileText className="h-3.5 w-3.5" />} />}{edit && <IconBtn onClick={edit} label="Edit" icon={<Edit3 className="h-3.5 w-3.5" />} />}{del && <IconBtn onClick={del} label="Delete" icon={<Trash2 className="h-3.5 w-3.5" />} />}</div>; }
function IconBtn({ onClick, icon, label }: { onClick: () => void; icon: React.ReactNode; label: string }) { return <button onClick={onClick} title={label} className="rounded-lg border border-white/10 bg-white/[0.03] p-1.5 text-white/55 hover:bg-white/[0.07]">{icon}</button>; }
function Empty({ text }: { text: string }) { return <div className="rounded-2xl border border-dashed border-white/10 p-8 text-center text-sm text-white/35">{text}</div>; }
function Mini({ k, v }: { k: string; v: React.ReactNode }) { return <div className="rounded-lg bg-white/[0.04] p-2"><div className="text-[9px] uppercase text-white/30">{k}</div><div className="truncate text-xs font-semibold text-white/80">{v}</div></div>; }
function Table({ heads, children }: { heads: string[]; children: React.ReactNode }) { return <div className="overflow-auto rounded-2xl border border-white/10 bg-white/[0.03]"><table className="w-full min-w-[820px] text-sm"><thead className="bg-white/[0.03] text-left text-[10px] uppercase tracking-wider text-white/35"><tr>{heads.map((h) => <th key={h} className="p-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-white/10 [&_td]:p-3 [&_td]:text-xs [&_td]:text-white/65">{children}</tbody></table></div>; }

function Dashboard({ stats, data, period, setTab, openPayment }: { stats: { units: number; occupied: number; rent: number; collected: number; overdue: number; orders: number }; data: Data; period: string; setTab: (t: Tab) => void; openPayment: (tenantId: string, amount: number) => void }) {
  const dueTenants = data.tenants.filter((t) => t.balance > 0).slice(0, 5);
  return <div className="space-y-4"><Title title="Dashboard" sub="At-a-glance KPIs, this month rent, work orders and lease action items." /><div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-4"><Metric label="Occupancy" value={`${stats.occupied}/${stats.units}`} sub="occupied units" /><Metric label="This Month Charged" value={currency(stats.rent, data.policy.currency)} sub={periodLabel(period)} /><Metric label="Collected" value={currency(stats.collected, data.policy.currency)} sub="payments received" /><Metric label="Open Work Orders" value={stats.orders} sub={`${stats.overdue} overdue charges`} /></div><div className="grid gap-4 xl:grid-cols-2"><Panel title="Due Tenants" action={<Button onClick={() => setTab('rent')} className="h-8 rounded-lg bg-blue-500/15 text-blue-300">Open ledger</Button>}>{dueTenants.length ? dueTenants.map((t) => <div key={t.id} className="mb-2 flex items-center justify-between rounded-xl border border-white/10 p-2"><Person tenant={t} /><div className="text-right"><div className="text-xs font-semibold text-amber-300">{currency(t.balance, data.policy.currency)}</div><button onClick={() => openPayment(t.id, t.balance)} className="text-[10px] text-blue-300">record payment</button></div></div>) : <Empty text="No tenant balances." />}</Panel><Panel title="Open Maintenance">{data.workOrders.filter((w) => !['Completed', 'Cancelled'].includes(w.status)).map((w) => <div key={w.id} className="mb-2 flex items-center justify-between rounded-xl border border-white/10 p-2"><div><div className="text-sm font-medium">{w.title}</div><div className="text-xs text-white/40">{propertyName(data, w.propertyId)} · {unitName(data, w.unitId)}</div></div><Badge s={w.status} /></div>)}</Panel></div></div>;
}
function Person({ tenant }: { tenant: Tenant }) { return <div className="flex min-w-0 items-center gap-2"><div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-full bg-blue-500/15 text-xs font-bold text-blue-200">{initials(tenant.name)}</div><div className="min-w-0"><div className="truncate text-sm font-medium text-white/90">{tenant.name}</div><div className="truncate text-[11px] text-white/40">{tenant.phone} · {tenant.shortCode}</div></div></div>; }

function PropertiesPage({ data, setForm, setDetail, remove, query }: { data: Data; setForm: (f: { kind: EntityKind; id?: string }) => void; setDetail: (d: { kind: DetailKind; id: string }) => void; remove: (k: EntityKind, id: string) => void; query: string }) { const rows = data.properties.filter((p) => `${p.name} ${p.address} ${p.city}`.toLowerCase().includes(query.toLowerCase())); return <div><Title title="Properties" sub="Cards, full detail pages, unit grids, notes and work orders." action="Add Property" onAction={() => setForm({ kind: 'property' })} /><div className="grid gap-3 md:grid-cols-2 xl:grid-cols-3">{rows.map((p) => <Card key={p.id} className="border-white/10 bg-white/[0.03]"><CardContent className="p-4"><div className="flex justify-between gap-3"><div><div className="font-semibold">{p.name}</div><div className="text-xs text-white/40">{p.type}</div></div><Badge s="Active" /></div><div className="mt-3 text-xs text-white/45"><MapPin className="mr-1 inline h-3.5 w-3.5" />{p.address}, {p.city}</div><div className="mt-3 grid grid-cols-3 gap-2"><Mini k="Units" v={p.units} /><Mini k="Occupied" v={p.occupied} /><Mini k="Monthly" v={currency(p.monthlyIncome, data.policy.currency)} /></div><div className="mt-3"><RowActions view={() => setDetail({ kind: 'property', id: p.id })} edit={() => setForm({ kind: 'property', id: p.id })} del={() => remove('property', p.id)} /></div></CardContent></Card>)}</div>{!rows.length && <Empty text="No properties found." />}</div>; }
function UnitsPage({ data, setForm, remove, query }: { data: Data; setForm: (f: { kind: EntityKind; id?: string }) => void; remove: (k: EntityKind, id: string) => void; query: string }) { const rows = data.units.filter((u) => `${u.number} ${u.type} ${u.tenantName || ''}`.toLowerCase().includes(query.toLowerCase())); return <div><Title title="Units" sub="Unit cards with rent, beds, baths, sqft, tenant and status." action="Add Unit" onAction={() => setForm({ kind: 'unit' })} /><div className="grid gap-3 md:grid-cols-2 xl:grid-cols-3">{rows.map((u) => <Card key={u.id} className="border-white/10 bg-white/[0.03]"><CardContent className="p-4"><div className="flex justify-between"><div><div className="font-semibold">{u.number}</div><div className="text-xs text-white/40">{propertyName(data, u.propertyId)}</div></div><Badge s={u.status} /></div><div className="mt-3 grid grid-cols-4 gap-2"><Mini k="Beds" v={u.beds} /><Mini k="Baths" v={u.baths} /><Mini k="Sqft" v={u.sqft || '—'} /><Mini k="Rent" v={currency(u.rent, data.policy.currency)} /></div><div className="mt-3 text-xs text-white/45">{u.tenantName || 'Vacant'}</div><div className="mt-3"><RowActions edit={() => setForm({ kind: 'unit', id: u.id })} del={() => remove('unit', u.id)} /></div></CardContent></Card>)}</div></div>; }
function TenantsPage({ data, setForm, setDetail, remove, openPayment, query }: { data: Data; setForm: (f: { kind: EntityKind; id?: string }) => void; setDetail: (d: { kind: DetailKind; id: string }) => void; remove: (k: EntityKind, id: string) => void; openPayment: (tenantId: string, amount: number) => void; query: string }) { const rows = data.tenants.filter((t) => `${t.name} ${t.phone} ${t.email} ${t.unit}`.toLowerCase().includes(query.toLowerCase())); return <div><Title title="Tenants" sub="Tenant list plus detail profile, lease history, payment history, notes and actions." action="Add Tenant" onAction={() => setForm({ kind: 'tenant' })} /><Table heads={['Tenant', 'Unit', 'Lease', 'Employer', 'Balance', 'Status', 'Actions']}>{rows.map((t) => <tr key={t.id}><td><Person tenant={t} /></td><td>{propertyName(data, t.propertyId)} · {t.unit}</td><td>{t.leaseStart} → {t.leaseEnd}</td><td>{t.employer || '—'}</td><td className="text-right text-amber-300">{currency(t.balance, data.policy.currency)}</td><td><Badge s={t.status} /></td><td><div className="flex justify-end gap-1"><Button onClick={() => openPayment(t.id, t.balance || t.monthlyRent)} className="h-8 bg-emerald-500/15 text-emerald-300"><CreditCard className="mr-1 h-3 w-3" />Pay</Button><RowActions view={() => setDetail({ kind: 'tenant', id: t.id })} edit={() => setForm({ kind: 'tenant', id: t.id })} del={() => remove('tenant', t.id)} /></div></td></tr>)}</Table></div>; }
function LeasesPage({ data, setForm, remove }: { data: Data; setForm: (f: { kind: EntityKind; id?: string }) => void; remove: (k: EntityKind, id: string) => void }) { return <div><Title title="Leases" sub="Term, monthly rent, deposit, due day, late fee and status editing." action="Add Lease" onAction={() => setForm({ kind: 'lease' })} /><Table heads={['Tenant', 'Unit', 'Term', 'Rent', 'Deposit', 'Due / Late', 'Status', 'Actions']}>{data.leases.map((l) => <tr key={l.id}><td>{tenantName(data, l.tenantId)}</td><td>{unitName(data, l.unitId)}</td><td>{l.start} → {l.end}</td><td>{currency(l.rent, data.policy.currency)}</td><td>{currency(l.deposit, data.policy.currency)}</td><td>Day {l.dueDay} · {currency(l.lateFee, data.policy.currency)}</td><td><Badge s={l.status} /></td><td><RowActions edit={() => setForm({ kind: 'lease', id: l.id })} del={() => remove('lease', l.id)} /></td></tr>)}</Table></div>; }
function RentPage({ data, period, setPeriod, generate, openPayment, removePayment, waive, exportCsv }: { data: Data; period: string; setPeriod: (p: string) => void; generate: () => void; openPayment: (tenantId: string, chargeId: string, amount: number) => void; removePayment: (id: string) => void; waive: (id: string) => void; exportCsv: (name: string, rows: Record<string, unknown>[]) => void }) { const [filter, setFilter] = useState('All'); const charges = data.charges.filter((c) => c.period === period && (filter === 'All' || c.status === filter)); const totals = charges.reduce((a, c) => ({ amount: a.amount + c.amount, paid: a.paid + c.paid }), { amount: 0, paid: 0 }); return <div className="space-y-3"><div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between"><Title title="Rent Ledger" sub="Generate charges, record/remove payments, waive charges, filter and export." /><div className="flex items-center gap-2"><Period period={period} setPeriod={setPeriod} /><Button onClick={generate} className="h-9 rounded-xl bg-blue-500">Generate</Button><Button onClick={() => exportCsv('rent-ledger', charges)} className="h-9 rounded-xl bg-white/10"><Download className="mr-1 h-4 w-4" />CSV</Button></div></div><div className="grid gap-3 sm:grid-cols-3"><Metric label="Charged" value={currency(totals.amount, data.policy.currency)} sub={periodLabel(period)} /><Metric label="Collected" value={currency(totals.paid, data.policy.currency)} sub="payments" /><Metric label="Outstanding" value={currency(totals.amount - totals.paid, data.policy.currency)} sub="balance" /></div><Filter value={filter} setValue={setFilter} values={['All', 'Open', 'Partial', 'Paid', 'Overdue', 'Waived']} /><Table heads={['Tenant', 'Unit', 'Due', 'Charge', 'Paid', 'Status', 'Actions']}>{charges.map((c) => { const due = Math.max(0, c.amount - c.paid); const payments = data.payments.filter((p) => p.chargeId === c.id); return <React.Fragment key={c.id}><tr><td>{tenantName(data, c.tenantId)}</td><td>{unitName(data, c.unitId)}</td><td>{c.dueDate}</td><td>{currency(c.amount, data.policy.currency)}</td><td>{currency(c.paid, data.policy.currency)}</td><td><Badge s={c.status} /></td><td><div className="flex justify-end gap-1">{due > 0 && <Button onClick={() => openPayment(c.tenantId, c.id, due)} className="h-8 bg-emerald-500/15 text-emerald-300">Record</Button>}<IconBtn onClick={() => waive(c.id)} label="Waive" icon={<AlertCircle className="h-3.5 w-3.5" />} /><IconBtn onClick={() => window.print()} label="Print" icon={<Printer className="h-3.5 w-3.5" />} /></div></td></tr>{payments.map((p) => <tr key={p.id} className="bg-white/[0.015]"><td colSpan={2}>Payment · {p.reference || 'No reference'}</td><td>{new Date(p.paidAt).toLocaleDateString()}</td><td>{p.method}</td><td>{currency(p.amount, data.policy.currency)}</td><td><Badge s="Paid" /></td><td><IconBtn onClick={() => removePayment(p.id)} label="Remove payment" icon={<Trash2 className="h-3.5 w-3.5" />} /></td></tr>)}</React.Fragment>; })}</Table></div>; }
function MaintenancePage({ data, setForm, setDetail, remove }: { data: Data; setForm: (f: { kind: EntityKind; id?: string }) => void; setDetail: (d: { kind: DetailKind; id: string }) => void; remove: (k: EntityKind, id: string) => void }) { const [filter, setFilter] = useState('Open'); const rows = data.workOrders.filter((w) => filter === 'All' || (filter === 'Unassigned' ? !w.vendorId : w.status === filter)); return <div><Title title="Maintenance" sub="Tabs, work-order details, vendor assignment, schedule, cost and status." action="New Work Order" onAction={() => setForm({ kind: 'workOrder' })} /><Filter value={filter} setValue={setFilter} values={['Open', 'Unassigned', 'Assigned', 'In Progress', 'Completed', 'All']} /><div className="mt-3 grid gap-3 md:grid-cols-2 xl:grid-cols-3">{rows.map((w) => <Card key={w.id} className="border-white/10 bg-white/[0.03]"><CardContent className="p-4"><div className="flex justify-between gap-3"><div><div className="font-semibold">{w.title}</div><div className="text-xs text-white/40">{propertyName(data, w.propertyId)} · {unitName(data, w.unitId)}</div></div><Badge s={w.priority} /></div><p className="mt-2 text-xs text-white/45">{w.description}</p><div className="mt-3 flex items-center justify-between"><Badge s={w.status} /><span className="text-xs text-white/45">{currency(w.cost, data.policy.currency)}</span></div><div className="mt-3"><RowActions view={() => setDetail({ kind: 'workOrder', id: w.id })} edit={() => setForm({ kind: 'workOrder', id: w.id })} del={() => remove('workOrder', w.id)} /></div></CardContent></Card>)}</div></div>; }
function VendorsPage({ data, setForm, setDetail, remove }: { data: Data; setForm: (f: { kind: EntityKind; id?: string }) => void; setDetail: (d: { kind: DetailKind; id: string }) => void; remove: (k: EntityKind, id: string) => void }) { const [cat, setCat] = useState('All'); const rows = data.vendors.filter((v) => cat === 'All' || v.category === cat); return <div><Title title="Vendors" sub="Directory, category filter, detail page and assigned work orders." action="Add Vendor" onAction={() => setForm({ kind: 'vendor' })} /><Filter value={cat} setValue={setCat} values={['All', 'Plumber', 'Electrician', 'HVAC', 'Handyman', 'Cleaning', 'Landscaping', 'General']} /><div className="mt-3 grid gap-3 md:grid-cols-2 xl:grid-cols-3">{rows.map((v) => <Card key={v.id} className="border-white/10 bg-white/[0.03]"><CardContent className="p-4"><div className="font-semibold">{v.name}</div><div className="text-xs text-blue-300">{v.category}</div><div className="mt-3 space-y-1 text-xs text-white/45"><div><Phone className="mr-1 inline h-3.5 w-3.5" />{v.phone}</div><div><Mail className="mr-1 inline h-3.5 w-3.5" />{v.email}</div></div><div className="mt-3"><RowActions view={() => setDetail({ kind: 'vendor', id: v.id })} edit={() => setForm({ kind: 'vendor', id: v.id })} del={() => remove('vendor', v.id)} /></div></CardContent></Card>)}</div></div>; }
function ApplicationsPage({ data, setForm, setDetail, remove, approve }: { data: Data; setForm: (f: { kind: EntityKind; id?: string }) => void; setDetail: (d: { kind: DetailKind; id: string }) => void; remove: (k: EntityKind, id: string) => void; approve: (id: string) => void }) { const [filter, setFilter] = useState('All'); const rows = data.applications.filter((a) => filter === 'All' || a.status === filter); return <div><Title title="Applications" sub="Applicant records, screening status, approve/decline and convert to tenant + lease." action="Add Application" onAction={() => setForm({ kind: 'application' })} /><Filter value={filter} setValue={setFilter} values={['All', 'New', 'Screening', 'Approved', 'Declined', 'Withdrawn']} /><Table heads={['Applicant', 'Unit', 'Employer', 'Income', 'Move-in', 'Status', 'Actions']}>{rows.map((a) => <tr key={a.id}><td>{a.firstName} {a.lastName}<div className="text-[11px] text-white/35">{a.phone}</div></td><td>{unitName(data, a.unitId)} · {propertyName(data, data.units.find((u) => u.id === a.unitId)?.propertyId)}</td><td>{a.employer}</td><td>{currency(a.income, data.policy.currency)}</td><td>{a.desiredMoveIn}</td><td><Badge s={a.status} /></td><td><div className="flex justify-end gap-1">{a.status !== 'Approved' && <Button onClick={() => approve(a.id)} className="h-8 bg-emerald-500/15 text-emerald-300">Approve</Button>}<RowActions view={() => setDetail({ kind: 'application', id: a.id })} edit={() => setForm({ kind: 'application', id: a.id })} del={() => remove('application', a.id)} /></div></td></tr>)}</Table></div>; }
function SettingsPage({ data, setData, exportCsv }: { data: Data; setData: React.Dispatch<React.SetStateAction<Data>>; exportCsv: (name: string, rows: Record<string, unknown>[]) => void }) { const [policy, setPolicy] = useState(data.policy); function save() { setData((old) => ({ ...old, policy })); } return <div className="grid gap-4 xl:grid-cols-2"><Panel title="Rent Policy Defaults"><div className="grid gap-3"><Labeled label="Default rent due day"><Input value={policy.dueDay} onChange={(e) => setPolicy({ ...policy, dueDay: Number(e.target.value) })} className="border-white/10 bg-white/[0.04]" /></Labeled><Labeled label="Late fee"><Input value={policy.lateFee} onChange={(e) => setPolicy({ ...policy, lateFee: Number(e.target.value) })} className="border-white/10 bg-white/[0.04]" /></Labeled><Labeled label="Grace days"><Input value={policy.graceDays} onChange={(e) => setPolicy({ ...policy, graceDays: Number(e.target.value) })} className="border-white/10 bg-white/[0.04]" /></Labeled><Labeled label="Currency"><Input value={policy.currency} onChange={(e) => setPolicy({ ...policy, currency: e.target.value })} className="border-white/10 bg-white/[0.04]" /></Labeled><Labeled label="Reminder channels"><Input value={policy.reminders} onChange={(e) => setPolicy({ ...policy, reminders: e.target.value })} className="border-white/10 bg-white/[0.04]" /></Labeled><Labeled label="Invoice prefix"><Input value={policy.invoicePrefix} onChange={(e) => setPolicy({ ...policy, invoicePrefix: e.target.value })} className="border-white/10 bg-white/[0.04]" /></Labeled><Button onClick={save} className="bg-blue-500">Save policy</Button></div></Panel><Panel title="Export / Print"><div className="grid gap-2"><Button onClick={() => exportCsv('tenants', data.tenants)} className="bg-white/10"><Download className="mr-1 h-4 w-4" />Export tenants CSV</Button><Button onClick={() => exportCsv('properties', data.properties)} className="bg-white/10"><Download className="mr-1 h-4 w-4" />Export properties CSV</Button><Button onClick={() => window.print()} className="bg-white/10"><Printer className="mr-1 h-4 w-4" />Print current view</Button></div></Panel></div>; }

function Period({ period, setPeriod }: { period: string; setPeriod: (p: string) => void }) { return <div className="flex items-center gap-1 rounded-xl border border-white/10 p-1"><button onClick={() => setPeriod(nextPeriod(period, -1))}><ChevronLeft className="h-4 w-4" /></button><span className="min-w-24 text-center text-xs">{periodLabel(period)}</span><button onClick={() => setPeriod(nextPeriod(period, 1))}><ChevronRight className="h-4 w-4" /></button></div>; }
function Filter({ value, setValue, values }: { value: string; setValue: (v: string) => void; values: string[] }) { return <div className="flex gap-1 overflow-x-auto pb-1">{values.map((v) => <button key={v} onClick={() => setValue(v)} className={`shrink-0 rounded-lg border px-2.5 py-1.5 text-[10px] ${value === v ? 'border-blue-500/25 bg-blue-500/15 text-blue-300' : 'border-white/10 bg-white/[0.03] text-white/45'}`}>{v}</button>)}</div>; }
function Labeled({ label, children }: { label: string; children: React.ReactNode }) { return <label className="grid gap-1 text-xs text-white/45"><span>{label}</span>{children}</label>; }

function EntityForm({ data, target, close, save }: { data: Data; target: { kind: EntityKind; id?: string }; close: () => void; save: (kind: EntityKind, id: string | undefined, values: Record<string, string>) => void }) { const current = getRecord(data, target.kind, target.id); const [values, setValues] = useState<Record<string, string>>(formInitial(target.kind, current)); const fields = formFields(target.kind, data); return <Modal title={`${target.id ? 'Edit' : 'Add'} ${target.kind}`} close={close}><div className="grid gap-3 md:grid-cols-2">{fields.map((f) => <Labeled key={f.name} label={f.label}>{f.type === 'select' ? <select value={values[f.name] || ''} onChange={(e) => setValues({ ...values, [f.name]: e.target.value })} className="h-10 rounded-xl border border-white/10 bg-[#101827] px-3 text-sm text-white">{f.options?.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}</select> : <Input type={f.type || 'text'} value={values[f.name] || ''} onChange={(e) => setValues({ ...values, [f.name]: e.target.value })} className="border-white/10 bg-white/[0.04]" />}</Labeled>)}</div><div className="mt-4 flex justify-end gap-2"><Button onClick={close} className="bg-white/10">Cancel</Button><Button onClick={() => save(target.kind, target.id, values)} className="bg-blue-500">Save</Button></div></Modal>; }
function PaymentModal({ data, target, close, save }: { data: Data; target: { tenantId: string; chargeId?: string; amount: number }; close: () => void; save: (v: { amount: number; method: string; reference: string; notes: string }) => void }) { const tenant = data.tenants.find((t) => t.id === target.tenantId); const [amount, setAmount] = useState(String(target.amount)); const [method, setMethod] = useState('Cash'); const [reference, setReference] = useState(`${data.policy.invoicePrefix}-${Date.now().toString().slice(-6)}`); const [notes, setNotes] = useState(''); const qr = JSON.stringify({ app: 'KobeOS Property', tenant: tenant?.shortCode, amount: Number(amount), reference }); return <Modal title="Record payment" close={close}><div className="grid gap-4 md:grid-cols-[160px_1fr]"><div className="rounded-2xl bg-white p-4"><QRCodeSVG value={qr} size={128} /><div className="mt-2 text-center text-[10px] text-black/60">{tenant?.shortCode}</div></div><div className="grid gap-3"><div className="text-sm font-medium">{tenant?.name}</div><Labeled label="Amount"><Input type="number" value={amount} onChange={(e) => setAmount(e.target.value)} className="border-white/10 bg-white/[0.04]" /></Labeled><Labeled label="Method"><select value={method} onChange={(e) => setMethod(e.target.value)} className="h-10 rounded-xl border border-white/10 bg-[#101827] px-3 text-sm text-white">{['Cash', 'Mobile Money', 'Bank Transfer', 'Card', 'KobePay'].map((m) => <option key={m}>{m}</option>)}</select></Labeled><Labeled label="Reference"><Input value={reference} onChange={(e) => setReference(e.target.value)} className="border-white/10 bg-white/[0.04]" /></Labeled><Labeled label="Notes"><Input value={notes} onChange={(e) => setNotes(e.target.value)} className="border-white/10 bg-white/[0.04]" /></Labeled><Button onClick={() => save({ amount: Number(amount), method, reference, notes })} className="bg-emerald-500"><CheckCircle2 className="mr-1 h-4 w-4" />Save Payment</Button></div></div></Modal>; }
function DetailModal({ data, target, close, setForm, openPayment }: { data: Data; target: { kind: DetailKind; id: string }; close: () => void; setForm: (f: { kind: EntityKind; id?: string }) => void; openPayment: (tenantId: string, amount: number) => void }) { const record = getRecord(data, target.kind, target.id) as Record<string, unknown> | undefined; if (!record) return null; const title = target.kind === 'tenant' ? String(record.name) : target.kind === 'property' ? String(record.name) : target.kind === 'application' ? `${record.firstName} ${record.lastName}` : String(record.title || record.name); return <Modal title={title} close={close}><div className="grid gap-4 xl:grid-cols-2"><Panel title="Details"><div className="grid gap-2">{Object.entries(record).filter(([k]) => k !== 'id').map(([k, v]) => <div key={k} className="flex justify-between gap-3 rounded-xl border border-white/10 p-2 text-xs"><span className="text-white/40">{k}</span><span className="text-right text-white/80">{String(v || '—')}</span></div>)}</div></Panel><Panel title="Related Actions"><div className="grid gap-2">{target.kind === 'tenant' && <Button onClick={() => openPayment(target.id, Number((record as Tenant).balance || (record as Tenant).monthlyRent))} className="bg-emerald-500/20 text-emerald-300"><CreditCard className="mr-1 h-4 w-4" />Record payment</Button>}<Button onClick={() => setForm({ kind: target.kind === 'workOrder' ? 'workOrder' : target.kind, id: target.id })} className="bg-blue-500"><Edit3 className="mr-1 h-4 w-4" />Edit</Button><Button onClick={() => window.print()} className="bg-white/10"><Printer className="mr-1 h-4 w-4" />Print</Button>{target.kind === 'tenant' && <TenantHistory data={data} tenantId={target.id} />}{target.kind === 'property' && <PropertyRelated data={data} propertyId={target.id} />}{target.kind === 'vendor' && <VendorRelated data={data} vendorId={target.id} />}</div></Panel></div></Modal>; }
function TenantHistory({ data, tenantId }: { data: Data; tenantId: string }) { return <div className="rounded-xl border border-white/10 p-3"><div className="mb-2 text-xs font-semibold">Payment history</div>{data.payments.filter((p) => p.tenantId === tenantId).map((p) => <div key={p.id} className="text-xs text-white/50">{new Date(p.paidAt).toLocaleDateString()} · {currency(p.amount, data.policy.currency)} · {p.reference}</div>)}</div>; }
function PropertyRelated({ data, propertyId }: { data: Data; propertyId: string }) { return <div className="rounded-xl border border-white/10 p-3"><div className="mb-2 text-xs font-semibold">Units</div>{data.units.filter((u) => u.propertyId === propertyId).map((u) => <div key={u.id} className="text-xs text-white/50">{u.number} · {u.status} · {currency(u.rent, data.policy.currency)}</div>)}</div>; }
function VendorRelated({ data, vendorId }: { data: Data; vendorId: string }) { return <div className="rounded-xl border border-white/10 p-3"><div className="mb-2 text-xs font-semibold">Assigned work orders</div>{data.workOrders.filter((w) => w.vendorId === vendorId).map((w) => <div key={w.id} className="text-xs text-white/50">{w.title} · {w.status}</div>)}</div>; }
function Modal({ title, close, children }: { title: string; close: () => void; children: React.ReactNode }) { return <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 p-4"><div className="max-h-[90vh] w-full max-w-4xl overflow-auto rounded-3xl border border-white/10 bg-[#0d111b] p-4 shadow-2xl"><div className="mb-4 flex items-center justify-between"><h3 className="text-base font-semibold capitalize">{title}</h3><button onClick={close} className="rounded-xl border border-white/10 p-2 text-white/50 hover:bg-white/5"><X className="h-4 w-4" /></button></div>{children}</div></div>; }

function formFields(kind: EntityKind, data: Data): Array<{ name: string; label: string; type?: string; options?: Array<{ value: string; label: string }> }> { const opts = (rows: Array<{ id: string; name?: string; number?: string; title?: string }>) => [{ value: '', label: '—' }, ...rows.map((r) => ({ value: r.id, label: r.name || r.number || r.title || r.id }))]; const base = { text: 'text', number: 'number', date: 'date', select: 'select' }; if (kind === 'property') return [{ name: 'name', label: 'Name' }, { name: 'type', label: 'Type' }, { name: 'address', label: 'Address' }, { name: 'city', label: 'City' }, { name: 'units', label: 'Units', type: base.number }, { name: 'occupied', label: 'Occupied', type: base.number }, { name: 'monthlyIncome', label: 'Monthly Income', type: base.number }, { name: 'color', label: 'Color' }, { name: 'notes', label: 'Notes' }]; if (kind === 'unit') return [{ name: 'propertyId', label: 'Property', type: base.select, options: opts(data.properties) }, { name: 'number', label: 'Unit Number' }, { name: 'type', label: 'Type' }, { name: 'beds', label: 'Beds', type: base.number }, { name: 'baths', label: 'Baths', type: base.number }, { name: 'sqft', label: 'Sqft', type: base.number }, { name: 'rent', label: 'Rent', type: base.number }, { name: 'status', label: 'Status', type: base.select, options: ['Vacant', 'Occupied', 'Turnover', 'Unavailable', 'Maintenance'].map((v) => ({ value: v, label: v })) }, { name: 'tenantId', label: 'Tenant', type: base.select, options: opts(data.tenants) }, { name: 'notes', label: 'Notes' }]; if (kind === 'tenant') return [{ name: 'name', label: 'Name' }, { name: 'phone', label: 'Phone' }, { name: 'email', label: 'Email' }, { name: 'unitId', label: 'Unit', type: base.select, options: opts(data.units) }, { name: 'leaseStart', label: 'Lease Start', type: base.date }, { name: 'leaseEnd', label: 'Lease End', type: base.date }, { name: 'monthlyRent', label: 'Monthly Rent', type: base.number }, { name: 'balance', label: 'Balance', type: base.number }, { name: 'status', label: 'Status' }, { name: 'employer', label: 'Employer' }, { name: 'income', label: 'Income', type: base.number }, { name: 'emergency', label: 'Emergency Contact' }, { name: 'notes', label: 'Notes' }]; if (kind === 'lease') return [{ name: 'tenantId', label: 'Tenant', type: base.select, options: opts(data.tenants) }, { name: 'unitId', label: 'Unit', type: base.select, options: opts(data.units) }, { name: 'start', label: 'Start', type: base.date }, { name: 'end', label: 'End', type: base.date }, { name: 'rent', label: 'Rent', type: base.number }, { name: 'deposit', label: 'Deposit', type: base.number }, { name: 'dueDay', label: 'Due Day', type: base.number }, { name: 'lateFee', label: 'Late Fee', type: base.number }, { name: 'status', label: 'Status' }, { name: 'notes', label: 'Notes' }]; if (kind === 'workOrder') return [{ name: 'propertyId', label: 'Property', type: base.select, options: opts(data.properties) }, { name: 'unitId', label: 'Unit', type: base.select, options: opts(data.units) }, { name: 'tenantId', label: 'Tenant', type: base.select, options: opts(data.tenants) }, { name: 'vendorId', label: 'Vendor', type: base.select, options: opts(data.vendors) }, { name: 'title', label: 'Title' }, { name: 'description', label: 'Description' }, { name: 'priority', label: 'Priority' }, { name: 'status', label: 'Status' }, { name: 'scheduledAt', label: 'Scheduled', type: base.date }, { name: 'completedAt', label: 'Completed', type: base.date }, { name: 'cost', label: 'Cost', type: base.number }, { name: 'notes', label: 'Notes' }]; if (kind === 'vendor') return [{ name: 'name', label: 'Name' }, { name: 'category', label: 'Category' }, { name: 'phone', label: 'Phone' }, { name: 'email', label: 'Email' }, { name: 'color', label: 'Color' }, { name: 'notes', label: 'Notes' }]; return [{ name: 'unitId', label: 'Unit', type: base.select, options: opts(data.units) }, { name: 'firstName', label: 'First Name' }, { name: 'lastName', label: 'Last Name' }, { name: 'phone', label: 'Phone' }, { name: 'email', label: 'Email' }, { name: 'employer', label: 'Employer' }, { name: 'income', label: 'Income', type: base.number }, { name: 'desiredMoveIn', label: 'Desired Move-in', type: base.date }, { name: 'status', label: 'Status' }, { name: 'notes', label: 'Notes' }]; }
function formInitial(kind: EntityKind, current?: unknown) { const src = (current || {}) as Record<string, unknown>; const out: Record<string, string> = {}; for (const [k, v] of Object.entries(src)) out[k] = String(v ?? ''); return out; }
function getRecord(data: Data, kind: EntityKind | DetailKind, id?: string) { if (!id) return undefined; const map = { property: data.properties, unit: data.units, tenant: data.tenants, lease: data.leases, workOrder: data.workOrders, vendor: data.vendors, application: data.applications }; return (map as Record<string, Array<{ id: string }>>)[kind]?.find((x) => x.id === id); }
function globalResults(data: Data, q: string) { const s = q.trim().toLowerCase(); if (!s) return []; const rows: Array<{ title: string; sub: string; tab: Tab; detail?: { kind: DetailKind; id: string } }> = []; data.properties.forEach((x) => `${x.name} ${x.address}`.toLowerCase().includes(s) && rows.push({ title: x.name, sub: 'Property', tab: 'properties', detail: { kind: 'property', id: x.id } })); data.tenants.forEach((x) => `${x.name} ${x.phone} ${x.email}`.toLowerCase().includes(s) && rows.push({ title: x.name, sub: 'Tenant', tab: 'tenants', detail: { kind: 'tenant', id: x.id } })); data.units.forEach((x) => `${x.number} ${x.tenantName}`.toLowerCase().includes(s) && rows.push({ title: x.number, sub: 'Unit', tab: 'units' })); data.workOrders.forEach((x) => x.title.toLowerCase().includes(s) && rows.push({ title: x.title, sub: 'Work order', tab: 'maintenance', detail: { kind: 'workOrder', id: x.id } })); data.vendors.forEach((x) => x.name.toLowerCase().includes(s) && rows.push({ title: x.name, sub: 'Vendor', tab: 'vendors', detail: { kind: 'vendor', id: x.id } })); data.applications.forEach((x) => `${x.firstName} ${x.lastName}`.toLowerCase().includes(s) && rows.push({ title: `${x.firstName} ${x.lastName}`, sub: 'Application', tab: 'applications', detail: { kind: 'application', id: x.id } })); return rows.slice(0, 8); }
function SearchBox({ results, open }: { results: ReturnType<typeof globalResults>; open: (r: ReturnType<typeof globalResults>[number]) => void }) { return <div className="absolute right-12 top-11 z-40 w-80 rounded-2xl border border-white/10 bg-[#0d111b] p-2 shadow-2xl">{results.length ? results.map((r) => <button key={`${r.tab}-${r.title}`} onClick={() => open(r)} className="block w-full rounded-xl p-2 text-left hover:bg-white/[0.05]"><div className="text-sm text-white/90">{r.title}</div><div className="text-[11px] text-white/40">{r.sub}</div></button>) : <div className="p-4 text-center text-xs text-white/35">No results</div>}</div>; }
